import{_ as t,o,c as r,ag as s}from"./chunks/framework.OsDJF_Ea.js";const u=JSON.parse('{"title":"MCP Servers","description":"Register HTTP tool servers (MCP) whose tools become available as runbook steps.","frontmatter":{"title":"MCP Servers","description":"Register HTTP tool servers (MCP) whose tools become available as runbook steps."},"headers":[],"relativePath":"portals/runbook/mcp-servers.md","filePath":"portals/runbook/mcp-servers.md"}'),a={name:"portals/runbook/mcp-servers.md"};function n(i,e,l,d,c,h){return o(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="mcp-servers" tabindex="-1">MCP Servers <a class="header-anchor" href="#mcp-servers" aria-label="Permalink to &quot;MCP Servers&quot;">​</a></h1><p><strong>Route:</strong> <code>/rb/mcp-servers</code> · <strong>Edition:</strong> Pro+</p><p>MCP (Model Context Protocol) servers are HTTP tool servers that expose callable tools. Once registered, their tools are available as steps inside any runbook.</p><h2 id="adding-an-mcp-server" tabindex="-1">Adding an MCP server <a class="header-anchor" href="#adding-an-mcp-server" aria-label="Permalink to &quot;Adding an MCP server&quot;">​</a></h2><p>Click <strong>+ Add Server</strong> and provide:</p><table tabindex="0"><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td>Name</td><td>Display name (e.g. &quot;Internal Toolbox&quot;)</td></tr><tr><td>Description</td><td>What tools this server provides</td></tr><tr><td>URL</td><td>Base URL of the MCP server (e.g. <code>http://mcp.internal:8000</code>)</td></tr><tr><td>Auth type</td><td>None / API Key / Bearer token</td></tr><tr><td>Auth config</td><td>Key or token value for the selected auth type</td></tr></tbody></table><h2 id="testing-the-connection" tabindex="-1">Testing the connection <a class="header-anchor" href="#testing-the-connection" aria-label="Permalink to &quot;Testing the connection&quot;">​</a></h2><p>Click <strong>Test</strong> on any server to send a health/list probe. The result shows whether the server is reachable and, if so, which tools it exposes.</p><h2 id="using-mcp-tools-in-runbooks" tabindex="-1">Using MCP tools in runbooks <a class="header-anchor" href="#using-mcp-tools-in-runbooks" aria-label="Permalink to &quot;Using MCP tools in runbooks&quot;">​</a></h2><p>In the runbook builder, add an <strong>MCP</strong> step and select:</p><ol><li>The registered MCP server</li><li>The tool name (from the server&#39;s tool list)</li><li>The arguments (JSON object)</li></ol><p>The step calls the tool and stores its response as the step output, available to subsequent steps via condition logic.</p>',12)])])}const b=t(a,[["render",n]]);export{u as __pageData,b as default};
